// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

	if (isLoading || newValue === '') {
		// STRY0094481
		var primaryOfficeEnabled = (g_form.getValue('parent') +'' == '' && (g_form.getValue('tasking_authority.u_external_flag') +'' == 'true' || g_scratchpad.primary_office_must_match_Internal_tasking_authority != 'true'));

		g_form.setReadOnly('primary_office',!primaryOfficeEnabled);
		g_form.setDisabled('primary_office',!primaryOfficeEnabled);
		return;
	}
	if (oldValue != ""){
		if (g_scratchpad.calchaschildren>0){
			postInfoMessage();
		} else {
			callbackToCheckForChildrenAndInfoMessage();
		}
	}

	var OUPermissions  = new GlideAjax('ClientUserInfoScripts');
	OUPermissions.addParam('sysparm_name','isOUExternalTA');
	OUPermissions.addParam("OU", g_form.getValue('tasking_authority'));
	var answer2 = false;
	// call script include to determine if this user is a tasking authority of the primary assignee OU.
	OUPermissions.getXML(f_returnIsTAExternal);

	function f_returnIsTAExternal(response) {
		var answer2 = response.responseXML.documentElement.getAttribute("answer");
		var isTAExternal = answer2 == 'true';
		var blnChangeAssignment = true;
		// RAJ 2018-02-13 if there was a Tasking Authority assigned, check if the task has children.
		if (newValue) {
			//	if (newValue != oldValue) { //STRY0043745
			// 8-16-19 Copy the value of the Tasking Authorty into the primary office
			if (newValue != '' && !isTAExternal){
				// STRY0071489 If new setting for system property definie if Primary Office Must Match Internal Tasking Authority
				if(g_scratchpad.primary_office_must_match_Internal_tasking_authority == 'true'){
					g_form.setValue('primary_office',newValue);
					g_form.setReadOnly('primary_office',true);
					g_form.setDisabled('primary_office',true);
				}
				g_form.hideFieldMsg('tasking_authority');
			} else{
				g_form.setReadOnly('primary_office',false);
				g_form.setDisabled('primary_office',false);
				// STRY0074601
				g_form.showFieldMsg("tasking_authority", getMessage('Tasker - The OU selected is an external Organizational Unit'), "info");
			}

		}
	}

	// STRY0154923 - removing an update of parent task in the after update caused the calculated 
	function callbackToCheckForChildrenAndInfoMessage(){
		var checkOrPublish = new GlideAjax("ClientTaskInfo");
		checkOrPublish.addParam('sysparm_name', 'taskParentHasSubtasks');
		checkOrPublish.addParam('parentID', g_form.getUniqueValue());
		checkOrPublish.getXML(checkForChildrenAndInfoMessage);
	}

	function checkForChildrenAndInfoMessage(response){
		var numberOfChildren = parseInt(response.responseXML.documentElement.getAttribute("answer"));
		if (numberOfChildren > 0 || g_scratchpad.u_create_multiple_subtasks) {
			postInfoMessage();
		}
	}
	function postInfoMessage(){
		g_form.addInfoMessage(getMessage('Tasker - Changing the Tasking Authority Updates All Descendant Tasks'));
	}	
}
